import {
  ChevronDown,
  ChevronRight,
  CircleDot,
  FileText,
  Folder,
  FolderOpen,
  Star,
  GitPullRequest,
  Loader2,
  Filter,
  Activity,
  CheckCircle2,
  XCircle,
  AlertTriangle,
  Clock,
  Circle,
  MinusCircle,
} from 'lucide-react'
import type { OrgRepo, RepoCounts } from '../../../api/github'
import type { PullRequest } from '../../../types/pullRequest'
import type { SFLRepoStatus, SFLOverallStatus } from '../../../types/sflStatus'
import { SFL_STATUS_LABELS } from '../../../types/sflStatus'
import { createPRDetailViewId } from '../../../utils/prDetailView'
import type { PRDetailSection } from '../../../utils/prDetailView'
import { dataCache } from '../../../services/dataCache'

interface OrgMeta {
  authenticatedAs: string
  isUserNamespace: boolean
}

interface OrgRepoTreeProps {
  uniqueOrgs: string[]
  orgRepos: Record<string, OrgRepo[]>
  orgMeta: Record<string, OrgMeta>
  loadingOrgs: Set<string>
  expandedOrgs: Set<string>
  expandedRepos: Set<string>
  expandedRepoPRGroups: Set<string>
  expandedPRNodes: Set<string>
  repoCounts: Record<string, RepoCounts>
  loadingRepoCounts: Set<string>
  repoPrTreeData: Record<string, PullRequest[]>
  sflStatusData: Record<string, SFLRepoStatus>
  loadingSFLStatus: Set<string>
  expandedSFLGroups: Set<string>
  bookmarkedRepoKeys: Set<string>
  showBookmarkedOnly: boolean
  selectedItem: string | null
  refreshTick: number
  onToggleOrg: (org: string) => void
  onToggleRepo: (org: string, repoName: string) => void
  onToggleRepoPRGroup: (org: string, repoName: string) => void
  onToggleSFLGroup: (org: string, repoName: string) => void
  onTogglePRNode: (prViewId: string) => void
  onItemSelect: (itemId: string) => void
  onContextMenu: (e: React.MouseEvent, pr: PullRequest) => void
  onBookmarkToggle: (e: React.MouseEvent, org: string, repoName: string, repoUrl: string) => void
  onToggleShowBookmarkedOnly: () => void
}

const prSubNodes: Array<{ key=[REDACTED] label: string }> = [
  { key=[REDACTED] label: 'Conversation' },
  { key=[REDACTED] label: 'Commits' },
  { key=[REDACTED] label: 'Checks' },
  { key=[REDACTED] label: 'Files changed' },
  { key=[REDACTED] label: 'AI Reviews' },
]

function formatUpdatedAge(fetchedAt: number): string {
  const elapsedMs = Date.now() - fetchedAt
  if (elapsedMs < 60_000) return 'updated now'
  const elapsedMinutes = Math.floor(elapsedMs / 60_000)
  if (elapsedMinutes < 60) return `updated ${elapsedMinutes}m ago`
  const elapsedHours = Math.floor(elapsedMinutes / 60)
  return `updated ${elapsedHours}h ago`
}

function sflOverallStatusIcon(status: SFLOverallStatus) {
  switch (status) {
    case 'healthy': return <CheckCircle2 size={12} className="sfl-status-icon sfl-status-success" />
    case 'active-work': return <Clock size={12} className="sfl-status-icon sfl-status-info" />
    case 'blocked': return <AlertTriangle size={12} className="sfl-status-icon sfl-status-warning" />
    case 'ready-for-review': return <CircleDot size={12} className="sfl-status-icon sfl-status-info" />
    case 'recent-failure': return <XCircle size={12} className="sfl-status-icon sfl-status-error" />
    default: return <Circle size={12} className="sfl-status-icon sfl-status-muted" />
  }
}

function sflWorkflowStateIcon(state: string, conclusion: string | null) {
  if (state !== 'active') return <MinusCircle size={11} className="sfl-status-icon sfl-status-muted" title="Disabled" />
  if (!conclusion) return <Circle size={11} className="sfl-status-icon sfl-status-muted" title="No runs" />
  switch (conclusion) {
    case 'success': return <CheckCircle2 size={11} className="sfl-status-icon sfl-status-success" title="Success" />
    case 'failure':
    case 'timed_out': return <XCircle size={11} className="sfl-status-icon sfl-status-error" title="Failed" />
    case 'skipped': return <MinusCircle size={11} className="sfl-status-icon sfl-status-muted" title="Skipped" />
    default: return <Clock size={11} className="sfl-status-icon sfl-status-info" title={conclusion} />
  }
}

export function OrgRepoTree({
  uniqueOrgs,
  orgRepos,
  orgMeta,
  loadingOrgs,
  expandedOrgs,
  expandedRepos,
  expandedRepoPRGroups,
  expandedPRNodes,
  repoCounts,
  loadingRepoCounts,
  repoPrTreeData,
  sflStatusData,
  loadingSFLStatus,
  expandedSFLGroups,
  bookmarkedRepoKeys,
  showBookmarkedOnly,
  selectedItem,
  refreshTick,
  onToggleOrg,
  onToggleRepo,
  onToggleRepoPRGroup,
  onToggleSFLGroup,
  onTogglePRNode,
  onItemSelect,
  onContextMenu,
  onBookmarkToggle,
  onToggleShowBookmarkedOnly,
}: OrgRepoTreeProps) {
  return (
    <div className="sidebar-section">
      <div className="sidebar-section-header" role="button" tabIndex={0} onClick={() => {}} onKeyDown={() => {}}>
        <div className="sidebar-section-title">
          <ChevronDown size={14} />
          <span className="sidebar-section-icon">
            <Folder size={16} />
          </span>
          <span>Organizations</span>
        </div>
        <button
          className={`sidebar-filter-btn ${showBookmarkedOnly ? 'active' : ''}`}
          onClick={e => {
            e.stopPropagation()
            onToggleShowBookmarkedOnly()
          }}
          title={showBookmarkedOnly ? 'Showing bookmarked only' : 'Showing all repos'}
        >
          <Filter size={14} />
        </button>
      </div>
      <div className="sidebar-section-items">
        {uniqueOrgs.length === 0 ? (
          <div className="sidebar-item sidebar-item-empty">
            <span className="sidebar-item-label">No accounts configured</span>
          </div>
        ) : (
          uniqueOrgs.map(org => {
            const isOrgExpanded = expandedOrgs.has(org)
            const isLoading = loadingOrgs.has(org)
            const repos = orgRepos[org] ?? []
            const meta = orgMeta[org]
            const filteredRepos = showBookmarkedOnly
              ? repos.filter(r => bookmarkedRepoKeys.has(`${org}/${r.name}`))
              : repos

            return (
              <div key={org} className="sidebar-org-group">
                <div className="sidebar-item sidebar-item-disclosure sidebar-org-item" role="button" tabIndex={0} onClick={() => onToggleOrg(org)} onKeyDown={e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); onToggleOrg(org) } }}>
                  <span className="sidebar-item-chevron">
                    {isOrgExpanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                  </span>
                  <span className="sidebar-item-icon">
                    {isOrgExpanded ? <FolderOpen size={14} /> : <Folder size={14} />}
                  </span>
                  <span className="sidebar-item-label">{org}</span>
                  {meta?.isUserNamespace && (
                    <span className="sidebar-namespace-badge" title="User account (not an org)">user</span>
                  )}
                  {isLoading && <Loader2 size={12} className="spin" />}
                  {!isLoading && repos.length > 0 && (
                    <span className="sidebar-item-count">
                      {showBookmarkedOnly ? filteredRepos.length : repos.length}
                    </span>
                  )}
                </div>
                {meta && !isLoading && (
                  <div className="sidebar-org-account" title={`Authenticated via @${meta.authenticatedAs}`}>
                    via @{meta.authenticatedAs}
                  </div>
                )}
                {isOrgExpanded && (
                  <div className="sidebar-org-repos">
                    {isLoading ? (
                      <div className="sidebar-item sidebar-item-empty">
                        <Loader2 size={12} className="spin" />
                        <span className="sidebar-item-label">Loading repos...</span>
                      </div>
                    ) : filteredRepos.length === 0 ? (
                      <div className="sidebar-item sidebar-item-empty">
                        <span className="sidebar-item-label">
                          {showBookmarkedOnly ? 'No bookmarked repos' : 'No repos found'}
                        </span>
                      </div>
                    ) : (
                      filteredRepos.map(repo => {
                        const isBookmarked = bookmarkedRepoKeys.has(`${org}/${repo.name}`)
                        const repoKey = `${org}/${repo.name}`
                        const isRepoExpanded = expandedRepos.has(repoKey)
                        const counts = repoCounts[repoKey]
                        const repoCountsEntry = dataCache.get<RepoCounts>(`repo-counts:${repoKey}`)
                        const repoCountsUpdatedLabel = repoCountsEntry?.fetchedAt
                          ? formatUpdatedAge(repoCountsEntry.fetchedAt)
                          : null
                        const isCountLoading = loadingRepoCounts.has(repoKey)

                        return (
                          <div key=[REDACTED] className="sidebar-repo-group">
                            <div
                              className="sidebar-item sidebar-item-disclosure sidebar-repo-item"
                              onClick={() => onToggleRepo(org, repo.name)}
                              title={repo.description || repo.fullName}
                            >
                              <span className="sidebar-item-chevron">
                                {isRepoExpanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                              </span>
                              <span className="sidebar-item-icon">
                                {isRepoExpanded ? <FolderOpen size={12} /> : <Folder size={12} />}
                              </span>
                              <span className="sidebar-item-label">{repo.name}</span>
                              {repo.language && <span className="sidebar-repo-lang">{repo.language}</span>}
                              <button
                                className={`sidebar-bookmark-btn ${isBookmarked ? 'active' : ''}`}
                                onClick={e => onBookmarkToggle(e, org, repo.name, repo.url)}
                                title={isBookmarked ? 'Remove bookmark' : 'Bookmark this repo'}
                              >
                                <Star size={12} fill={isBookmarked ? 'currentColor' : 'none'} />
                              </button>
                            </div>
                            {isRepoExpanded && (
                              <div className="sidebar-repo-children">
                                <div
                                  className={`sidebar-item sidebar-repo-child ${selectedItem === `repo-detail:${repoKey}` ? 'selected' : ''}`}
                                  onClick={() => onItemSelect(`repo-detail:${repoKey}`)}
                                >
                                  <span className="sidebar-item-icon"><FileText size={12} /></span>
                                  <span className="sidebar-item-label">Overview</span>
                                </div>
                                <div
                                  className={`sidebar-item sidebar-repo-child ${selectedItem === `repo-issues:${repoKey}` ? 'selected' : ''}`}
                                  onClick={() => onItemSelect(`repo-issues:${repoKey}`)}
                                >
                                  <span className="sidebar-item-icon"><CircleDot size={12} /></span>
                                  <span className="sidebar-item-label">Issues</span>
                                  {isCountLoading ? <Loader2 size={10} className="spin" /> : counts ? <span className="sidebar-item-count">{counts.issues}</span> : null}
                                </div>
                                <div
                                  className={`sidebar-item sidebar-item-disclosure sidebar-repo-child sidebar-repo-pr-row ${selectedItem === `repo-prs:${repoKey}` ? 'selected' : ''}`}
                                  onClick={() => { onItemSelect(`repo-prs:${repoKey}`); onToggleRepoPRGroup(org, repo.name) }}
                                >
                                  <span className="sidebar-item-chevron" onClick={e => { e.stopPropagation(); onToggleRepoPRGroup(org, repo.name) }}>
                                    {expandedRepoPRGroups.has(repoKey) ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                                  </span>
                                  <span className="sidebar-item-icon"><GitPullRequest size={12} /></span>
                                  <span className="sidebar-item-label">Pull Requests</span>
                                  {isCountLoading ? <Loader2 size={10} className="spin" /> : counts ? <span className="sidebar-item-count">{counts.prs}</span> : null}
                                  {!isCountLoading && repoCountsUpdatedLabel && (
                                    <span key=[REDACTED] className="sidebar-item-updated-age">{repoCountsUpdatedLabel}</span>
                                  )}
                                </div>
                                {expandedRepoPRGroups.has(repoKey) && (repoPrTreeData[repoKey] || []).length > 0 && (
                                  <div className="sidebar-job-tree sidebar-repo-pr-tree">
                                    <div className="sidebar-job-items">
                                      {(repoPrTreeData[repoKey] || []).map(pr => {
                                        const prViewId = createPRDetailViewId(pr)
                                        const isSelected = selectedItem === prViewId || selectedItem?.startsWith(`${prViewId}?section=`)
                                        return (
                                          <div key=[REDACTED] className="sidebar-pr-group">
                                            <div
                                              className={`sidebar-item sidebar-item-disclosure sidebar-pr-item sidebar-repo-pr-item ${isSelected ? 'selected' : ''}`}
                                              onClick={() => onItemSelect(prViewId)}
                                              onContextMenu={e => onContextMenu(e, pr)}
                                              title={pr.title}
                                            >
                                              <span className="sidebar-item-chevron" onClick={e => { e.stopPropagation(); onTogglePRNode(prViewId) }}>
                                                {expandedPRNodes.has(prViewId) ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                                              </span>
                                              <span className="sidebar-item-icon"><GitPullRequest size={12} /></span>
                                              <span className="sidebar-item-label">#{pr.id} {pr.title}</span>
                                              <span className="sidebar-pr-meta">{pr.repository}</span>
                                            </div>
                                            {expandedPRNodes.has(prViewId) && (
                                              <div className="sidebar-pr-children">
                                                {prSubNodes.map(node => {
                                                  const childViewId = createPRDetailViewId(pr, node.key)
                                                  return (
                                                    <div
                                                      key=[REDACTED]                                                      className={`sidebar-item sidebar-pr-child ${selectedItem === childViewId ? 'selected' : ''}`}
                                                      onClick={() => onItemSelect(childViewId)}
                                                    >
                                                      <span className="sidebar-item-icon"><FileText size={11} /></span>
                                                      <span className="sidebar-item-label">{node.label}</span>
                                                    </div>
                                                  )
                                                })}
                                              </div>
                                            )}
                                          </div>
                                        )
                                      })}
                                    </div>
                                  </div>
                                )}
                                {/* SFL Loop node */}
                                {(() => {
                                  const sflStatus = sflStatusData[repoKey]
                                  const isSFLLoading = loadingSFLStatus.has(repoKey)
                                  const isSFLExpanded = expandedSFLGroups.has(repoKey)
                                  if (sflStatus && !sflStatus.isSFLEnabled) return null
                                  if (!sflStatus && !isSFLLoading && !isSFLExpanded) {
                                    return (
                                      <div
                                        className="sidebar-item sidebar-item-disclosure sidebar-repo-child"
                                        onClick={() => onToggleSFLGroup(org, repo.name)}
                                      >
                                        <span className="sidebar-item-chevron">
                                          <ChevronRight size={12} />
                                        </span>
                                        <span className="sidebar-item-icon"><Activity size={12} /></span>
                                        <span className="sidebar-item-label">SFL Loop</span>
                                      </div>
                                    )
                                  }
                                  return (
                                    <>
                                      <div
                                        className="sidebar-item sidebar-item-disclosure sidebar-repo-child"
                                        onClick={() => onToggleSFLGroup(org, repo.name)}
                                      >
                                        <span className="sidebar-item-chevron" onClick={e => { e.stopPropagation(); onToggleSFLGroup(org, repo.name) }}>
                                          {isSFLExpanded ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                                        </span>
                                        <span className="sidebar-item-icon"><Activity size={12} /></span>
                                        <span className="sidebar-item-label">SFL Loop</span>
                                        {isSFLLoading && <Loader2 size={10} className="spin" />}
                                        {sflStatus?.isSFLEnabled && !isSFLLoading && (
                                          <span className="sidebar-sfl-status-badge" title={SFL_STATUS_LABELS[sflStatus.overallStatus]}>
                                            {sflOverallStatusIcon(sflStatus.overallStatus)}
                                          </span>
                                        )}
                                      </div>
                                      {isSFLExpanded && sflStatus?.isSFLEnabled && (
                                        <div className="sidebar-job-tree sidebar-sfl-tree">
                                          <div className="sidebar-job-items">
                                            <div className="sidebar-item sidebar-sfl-summary">
                                              {sflOverallStatusIcon(sflStatus.overallStatus)}
                                              <span className="sidebar-item-label">{SFL_STATUS_LABELS[sflStatus.overallStatus]}</span>
                                              <span className="sidebar-item-count">{sflStatus.workflows.length}</span>
                                            </div>
                                            {sflStatus.workflows.map(wf => (
                                              <div
                                                key=[REDACTED]                                                className="sidebar-item sidebar-sfl-workflow"
                                                title={`${wf.name} ŌĆö ${wf.state === 'active' ? 'enabled' : 'disabled'}${wf.latestRun ? `, last: ${wf.latestRun.conclusion || wf.latestRun.status}` : ''}`}
                                              >
                                                {sflWorkflowStateIcon(wf.state, wf.latestRun?.conclusion ?? null)}
                                                <span className="sidebar-item-label">{wf.name.replace(/^SFL:\s*/i, '')}</span>
                                                {wf.state !== 'active' && <span className="sidebar-sfl-disabled-badge">off</span>}
                                              </div>
                                            ))}
                                          </div>
                                        </div>
                                      )}
                                      {isSFLExpanded && !sflStatus?.isSFLEnabled && !isSFLLoading && (
                                        <div className="sidebar-job-tree sidebar-sfl-tree">
                                          <div className="sidebar-job-items">
                                            <div className="sidebar-item sidebar-sfl-summary">
                                              <span className="sidebar-item-label">No SFL workflows detected</span>
                                            </div>
                                          </div>
                                        </div>
                                      )}
                                    </>
                                  )
                                })()}
                              </div>
                            )}
                          </div>
                        )
                      })
                    )}
                  </div>
                )}
              </div>
            )
          })
        )}
      </div>
    </div>
  )
}

import { useState, useEffect, useCallback, useRef, useMemo } from 'react'
import { useGitHubAccounts, usePRSettings } from '../../../hooks/useConfig'
import {
  useRepoBookmarks,
  useRepoBookmarkMutations,
  useBuddyStatsMutations,
} from '../../../hooks/useConvex'
import { useTaskQueue } from '../../../hooks/useTaskQueue'
import {
  GitHubClient,
  type OrgRepo,
  type OrgRepoResult,
  type RepoCounts,
  type RepoPullRequest,
} from '../../../api/github'
import { dataCache } from '../../../services/dataCache'
import { parseOwnerRepoFromUrl } from '../../../utils/githubUrl'
import type { PullRequest } from '../../../types/pullRequest'
import type { SFLRepoStatus } from '../../../types/sflStatus'
import { MS_PER_MINUTE } from '../../../constants'

export interface SidebarItem {
  id: string
  label: string
}

function mapRepoPRToPullRequest(pr: RepoPullRequest, org: string): PullRequest {
  return {
    source: 'GitHub',
    repository: pr.url.split('/')[4] || pr.url,
    id: pr.number,
    title: pr.title,
    author: pr.author,
    authorAvatarUrl: pr.authorAvatarUrl || undefined,
    url: pr.url,
    state: pr.state,
    approvalCount: pr.approvalCount ?? 0,
    assigneeCount: pr.assigneeCount ?? 0,
    iApproved: pr.iApproved ?? false,
    created: pr.createdAt ? new Date(pr.createdAt) : null,
    updatedAt: pr.updatedAt,
    headBranch: pr.headBranch,
    baseBranch: pr.baseBranch,
    date: pr.updatedAt || pr.createdAt,
    org,
  }
}

export function useGitHubSidebarData() {
  const [expandedSections, setExpandedSections] = useState<Set<string>>(
    new Set(['pull-requests', 'organizations'])
  )
  const [expandedOrgs, setExpandedOrgs] = useState<Set<string>>(new Set())
  const [showBookmarkedOnly, setShowBookmarkedOnly] = useState(false)

  useEffect(() => {
    window.ipcRenderer
      .invoke('config:get-show-bookmarked-only')
      .then((value: boolean) => {
        setShowBookmarkedOnly(value)
      })
      .catch(() => {
        /* use default */
      })
  }, [])

  const [orgRepos, setOrgRepos] = useState<Record<string, OrgRepo[]>>({})
  const [orgMeta, setOrgMeta] = useState<
    Record<string, { authenticatedAs: string; isUserNamespace: boolean }>
  >({})
  const [loadingOrgs, setLoadingOrgs] = useState<Set<string>>(new Set())
  const { accounts } = useGitHubAccounts()
  const { refreshInterval } = usePRSettings()
  const bookmarks = useRepoBookmarks()
  const { create: createBookmark, remove: removeBookmark } = useRepoBookmarkMutations()
  const { enqueue } = useTaskQueue('github')
  const enqueueRef = useRef(enqueue)
  useEffect(() => {
    enqueueRef.current = enqueue
  }, [enqueue])
  const refreshTimerRef = useRef<ReturnType<typeof setInterval> | null>(null)
  const { increment: incrementStat } = useBuddyStatsMutations()

  const [expandedRepos, setExpandedRepos] = useState<Set<string>>(new Set())
  const [repoCounts, setRepoCounts] = useState<Record<string, RepoCounts>>({})
  const [loadingRepoCounts, setLoadingRepoCounts] = useState<Set<string>>(new Set())
  const fetchedCountsRef = useRef<Set<string>>(new Set())
  const [expandedPrGroups, setExpandedPrGroups] = useState<Set<string>>(new Set())
  const [prContextMenu, setPrContextMenu] = useState<{ x: number; y: number; pr: PullRequest } | null>(
    null
  )
  const [approvingPrKey, setApprovingPrKey] = useState<string | null>(null)
  const [expandedPRNodes, setExpandedPRNodes] = useState<Set<string>>(new Set())
  const [expandedRepoPRGroups, setExpandedRepoPRGroups] = useState<Set<string>>(new Set())
  const [refreshTick, setRefreshTick] = useState(() => Date.now())
  const [repoPrTreeData, setRepoPrTreeData] = useState<Record<string, PullRequest[]>>({})
  const fetchedRepoPRsRef = useRef<Set<string>>(new Set())
  const [sflStatusData, setSflStatusData] = useState<Record<string, SFLRepoStatus>>({})
  const [loadingSFLStatus, setLoadingSFLStatus] = useState<Set<string>>(new Set())
  const [expandedSFLGroups, setExpandedSFLGroups] = useState<Set<string>>(new Set())
  const fetchedSFLRef = useRef<Set<string>>(new Set())
  const [prTreeData, setPrTreeData] = useState<Record<string, PullRequest[]>>(() => ({
    'pr-my-prs': dataCache.get<PullRequest[]>('my-prs')?.data || [],
    'pr-needs-review': dataCache.get<PullRequest[]>('needs-review')?.data || [],
    'pr-need-a-nudge': dataCache.get<PullRequest[]>('need-a-nudge')?.data || [],
    'pr-recently-merged': dataCache.get<PullRequest[]>('recently-merged')?.data || [],
  }))

  const uniqueOrgs: string[] = (Array.from(new Set(accounts.map((a: { org?: string }) => a.org))).filter(Boolean) as string[]).sort()

  useEffect(() => {
    const intervalId = setInterval(() => {
      setRefreshTick(Date.now())
    }, 60_000)
    return () => clearInterval(intervalId)
  }, [])

  const bookmarkedRepoKeys = useMemo(
    () => new Set((bookmarks ?? []).map(b => `${b.owner}/${b.repo}`)),
    [bookmarks]
  )

  useEffect(() => {
    for (const org of uniqueOrgs) {
      const cached = dataCache.get<OrgRepoResult>(`org-repos:${org}`)
      if (cached?.data && 'repos' in cached.data && Array.isArray(cached.data.repos)) {
        setOrgRepos(prev => ({ ...prev, [org]: cached.data.repos }))
        setOrgMeta(prev => ({
          ...prev,
          [org]: {
            authenticatedAs: cached.data.authenticatedAs,
            isUserNamespace: cached.data.isUserNamespace,
          },
        }))
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [uniqueOrgs.join(',')])

  useEffect(() => {
    const unsubscribe = dataCache.subscribe(key => {
      if (key.startsWith('org-repos:')) {
        const org = key.replace('org-repos:', '')
        const updated = dataCache.get<OrgRepoResult>(key)
        if (updated?.data && 'repos' in updated.data && Array.isArray(updated.data.repos)) {
          setOrgRepos(prev => ({ ...prev, [org]: updated.data.repos }))
          setOrgMeta(prev => ({
            ...prev,
            [org]: {
              authenticatedAs: updated.data.authenticatedAs,
              isUserNamespace: updated.data.isUserNamespace,
            },
          }))
        }
        return
      }
      if (key.startsWith('repo-counts:')) {
        const repoKey = key.replace('repo-counts:', '')
        const updated = dataCache.get<RepoCounts>(key)
        if (updated?.data) {
          setRepoCounts(prev => ({ ...prev, [repoKey]: updated.data }))
        }
        return
      }
      if (key.startsWith('repo-prs:')) {
        const repoKey = key.replace('repo-prs:', '')
        const updated = dataCache.get<RepoPullRequest[]>(key)
        if (!updated?.data) return
        const [org, ...repoParts] = repoKey.split('/')
        const repoName = repoParts.join('/')
        if (!org || !repoName) return
        setRepoPrTreeData(prev => ({
          ...prev,
          [repoKey]: updated.data.map(repoPr => mapRepoPRToPullRequest(repoPr, org)),
        }))
        return
      }
      if (key.startsWith('sfl-status:')) {
        const repoKey = key.replace('sfl-status:', '')
        const updated = dataCache.get<SFLRepoStatus>(key)
        if (updated?.data) {
          setSflStatusData(prev => ({ ...prev, [repoKey]: updated.data }))
        }
      }
    })
    return unsubscribe
  }, [])

  useEffect(() => {
    if (!refreshInterval || refreshInterval <= 0 || accounts.length === 0) return
    const intervalMs = refreshInterval * MS_PER_MINUTE
    const refreshAllOrgs = () => {
      const orgs = (Array.from(new Set(accounts.map(a => a.org))).filter(Boolean) as string[]).sort()
      for (const org of orgs) {
        const cacheKey = `org-repos:${org}`
        if (dataCache.isFresh(cacheKey, intervalMs)) continue
        console.log(`[OrgRefresh] ${org}: stale, queueing background refresh`)
        enqueueRef
          .current(
            async signal => {
              if (dataCache.isFresh(cacheKey, intervalMs)) return
              if (signal.aborted) throw new DOMException('Cancelled', 'AbortError')
              const config = { accounts }
              const client = new GitHubClient(config, 7)
              const result = await client.fetchOrgRepos(org)
              dataCache.set(cacheKey, result)
              console.log(`[OrgRefresh] ${String(org)}: refreshed ${result.repos.length} repos`)
            },
            { name: `refresh-org-${org}`, priority: -1 }
          )
          .catch(err => {
            if (err instanceof DOMException && err.name === 'AbortError') return
            console.warn(`[OrgRefresh] ${org} failed:`, err)
          })
      }
    }
    console.log(`[OrgRefresh] Setting up auto-refresh: ${refreshInterval} minutes`)
    refreshTimerRef.current = setInterval(refreshAllOrgs, intervalMs)
    return () => {
      if (refreshTimerRef.current) {
        clearInterval(refreshTimerRef.current)
        refreshTimerRef.current = null
      }
    }
  }, [refreshInterval, accounts])

  const toggleSection = (sectionId: string) => {
    setExpandedSections(prev => {
      const next = new Set(prev)
      if (next.has(sectionId)) next.delete(sectionId)
      else next.add(sectionId)
      return next
    })
  }

  const fetchOrgRepos = useCallback(
    async (org: string) => {
      const cached = dataCache.get<OrgRepoResult>(`org-repos:${org}`)
      if (cached?.data && 'repos' in cached.data && Array.isArray(cached.data.repos)) {
        setOrgRepos(prev => ({ ...prev, [org]: cached.data.repos }))
        setOrgMeta(prev => ({
          ...prev,
          [org]: {
            authenticatedAs: cached.data.authenticatedAs,
            isUserNamespace: cached.data.isUserNamespace,
          },
        }))
        return
      }
      if (cached?.data) {
        dataCache.delete(`org-repos:${org}`)
      }
      setLoadingOrgs(prev => new Set([...prev, org]))
      try {
        const result = await enqueueRef.current(
          async signal => {
            if (signal.aborted) throw new DOMException('Cancelled', 'AbortError')
            const config = { accounts }
            const client = new GitHubClient(config, 7)
            return await client.fetchOrgRepos(org)
          },
          { name: `fetch-org-${org}` }
        )
        setOrgRepos(prev => ({ ...prev, [org]: result.repos }))
        setOrgMeta(prev => ({
          ...prev,
          [org]: {
            authenticatedAs: result.authenticatedAs,
            isUserNamespace: result.isUserNamespace,
          },
        }))
        dataCache.set(`org-repos:${org}`, result)
      } catch (error) {
        if (error instanceof DOMException && error.name === 'AbortError') return
        console.error(`Failed to fetch repos for ${org}:`, error)
        setOrgRepos(prev => ({ ...prev, [org]: [] }))
      } finally {
        setLoadingOrgs(prev => {
          const next = new Set(prev)
          next.delete(org)
          return next
        })
      }
    },
    [accounts]
  )

  const toggleOrg = useCallback(
    (org: string) => {
      setExpandedOrgs(prev => {
        const next = new Set(prev)
        if (next.has(org)) {
          next.delete(org)
        } else {
          next.add(org)
          incrementStat({ field: 'reposBrowsed' }).catch(() => {})
          if (!orgRepos[org]) {
            fetchOrgRepos(org)
          }
        }
        return next
      })
    },
    [orgRepos, fetchOrgRepos, incrementStat]
  )

  const toggleBookmarkRepoByValues = useCallback(
    async (org: string, repoName: string, repoUrl: string) => {
      const key = `${org}/${repoName}`
      if (bookmarkedRepoKeys.has(key)) {
        const bookmark = (bookmarks ?? []).find(b => b.owner === org && b.repo === repoName)
        if (bookmark) {
          await removeBookmark({ id: bookmark._id })
        }
        return
      }
      await createBookmark({
        folder: org,
        owner: org,
        repo: repoName,
        url: repoUrl,
        description: '',
      })
      incrementStat({ field: 'bookmarksCreated' }).catch(() => {})
    },
    [bookmarkedRepoKeys, bookmarks, createBookmark, removeBookmark, incrementStat]
  )

  const handleBookmarkToggle = async (
    e: React.MouseEvent,
    org: string,
    repoName: string,
    repoUrl: string
  ) => {
    e.stopPropagation()
    await toggleBookmarkRepoByValues(org, repoName, repoUrl)
  }

  const fetchRepoCountsForRepo = useCallback(
    async (org: string, repoName: string, forceRefresh = false) => {
      const key = `${org}/${repoName}`
      const cacheKey = `repo-counts:${key}`
      const cached = dataCache.get<RepoCounts>(cacheKey)
      if (cached?.data && !forceRefresh) {
        setRepoCounts(prev => ({ ...prev, [key]: cached.data }))
        return
      }
      setLoadingRepoCounts(prev => new Set([...prev, key]))
      try {
        const result = await enqueueRef.current(
          async signal => {
            if (signal.aborted) throw new DOMException('Cancelled', 'AbortError')
            const config = { accounts }
            const client = new GitHubClient(config, 7)
            return await client.fetchRepoCounts(org, repoName)
          },
          { name: `repo-counts-${key}`, priority: -1 }
        )
        setRepoCounts(prev => ({ ...prev, [key]: result }))
        dataCache.set(cacheKey, result)
      } catch (error) {
        if (error instanceof DOMException && error.name === 'AbortError') return
        console.warn(`Failed to fetch counts for ${key}:`, error)
      } finally {
        setLoadingRepoCounts(prev => {
          const next = new Set(prev)
          next.delete(key)
          return next
        })
      }
    },
    [accounts]
  )

  const toggleRepo = useCallback(
    (org: string, repoName: string) => {
      const key = `${org}/${repoName}`
      const shouldFetch = !fetchedCountsRef.current.has(key)
      setExpandedRepos(prev => {
        const next = new Set(prev)
        if (next.has(key)) {
          next.delete(key)
        } else {
          next.add(key)
        }
        return next
      })
      if (shouldFetch) {
        fetchedCountsRef.current.add(key)
        fetchRepoCountsForRepo(org, repoName)
      }
    },
    [fetchRepoCountsForRepo]
  )

  const fetchRepoPRsForRepo = useCallback(
    async (org: string, repoName: string, forceRefresh = false) => {
      const key = `${org}/${repoName}`
      const cacheKey = `repo-prs:${key}`
      const maxAgeMs = refreshInterval > 0 ? refreshInterval * MS_PER_MINUTE : null
      const cached = dataCache.get<RepoPullRequest[]>(cacheKey)
      if (cached?.data && !forceRefresh) {
        setRepoPrTreeData(prev => ({
          ...prev,
          [key]: cached.data.map(repoPr => mapRepoPRToPullRequest(repoPr, org)),
        }))
        if (maxAgeMs && dataCache.isFresh(cacheKey, maxAgeMs)) {
          return
        }
      }
      try {
        const result = await enqueueRef.current(
          async signal => {
            if (signal.aborted) throw new DOMException('Cancelled', 'AbortError')
            const client = new GitHubClient({ accounts }, 7)
            return await client.fetchRepoPRs(org, repoName)
          },
          { name: `repo-pr-tree-${org}-${repoName}`, priority: -1 }
        )
        setRepoPrTreeData(prev => ({
          ...prev,
          [key]: result.map(repoPr => mapRepoPRToPullRequest(repoPr, org)),
        }))
        dataCache.set(cacheKey, result)
        const countsCacheKey = `repo-counts:${key}`
        const existingCounts = dataCache.get<RepoCounts>(countsCacheKey)
        dataCache.set(countsCacheKey, {
          issues: existingCounts?.data?.issues ?? 0,
          prs: result.length,
        })
      } catch (error) {
        if (error instanceof DOMException && error.name === 'AbortError') return
        console.warn(`[RepoPRTree] ${key} failed:`, error)
      }
    },
    [accounts, refreshInterval]
  )

  const toggleRepoPRGroup = useCallback(
    (org: string, repoName: string) => {
      const key = `${org}/${repoName}`
      const shouldFetch = !fetchedRepoPRsRef.current.has(key)
      setExpandedRepoPRGroups(prev => {
        const next = new Set(prev)
        if (next.has(key)) {
          next.delete(key)
        } else {
          next.add(key)
        }
        return next
      })
      if (shouldFetch) {
        fetchedRepoPRsRef.current.add(key)
        fetchRepoPRsForRepo(org, repoName)
      }
    },
    [fetchRepoPRsForRepo]
  )

  const fetchSFLStatusForRepo = useCallback(
    async (org: string, repoName: string, isRefresh = false) => {
      const key = `${org}/${repoName}`
      const cacheKey = `sfl-status:${key}`
      if (!isRefresh) {
        const cached = dataCache.get<SFLRepoStatus>(cacheKey)
        if (cached?.data) {
          setSflStatusData(prev => ({ ...prev, [key]: cached.data }))
          return
        }
      }
      setLoadingSFLStatus(prev => new Set([...prev, key]))
      try {
        const result = await enqueueRef.current(
          async signal => {
            if (signal.aborted) throw new DOMException('Cancelled', 'AbortError')
            const client = new GitHubClient({ accounts }, 7)
            return await client.fetchSFLStatus(org, repoName)
          },
          { name: `sfl-status-${key}`, priority: -1 }
        )
        setSflStatusData(prev => ({ ...prev, [key]: result }))
        dataCache.set(cacheKey, result)
      } catch (error) {
        if (error instanceof DOMException && error.name === 'AbortError') return
        console.warn(`[SFLStatus] ${key} failed:`, error)
      } finally {
        setLoadingSFLStatus(prev => {
          const next = new Set(prev)
          next.delete(key)
          return next
        })
      }
    },
    [accounts]
  )

  const toggleSFLGroup = useCallback(
    (org: string, repoName: string) => {
      const key = `${org}/${repoName}`
      const shouldFetch = !fetchedSFLRef.current.has(key)
      setExpandedSFLGroups(prev => {
        const next = new Set(prev)
        if (next.has(key)) {
          next.delete(key)
        } else {
          next.add(key)
        }
        return next
      })
      if (shouldFetch) {
        fetchedSFLRef.current.add(key)
        fetchSFLStatusForRepo(org, repoName)
      }
    },
    [fetchSFLStatusForRepo]
  )

  useEffect(() => {
    if (!refreshInterval || refreshInterval <= 0 || accounts.length === 0) return
    const intervalMs = refreshInterval * MS_PER_MINUTE
    const intervalId = setInterval(() => {
      for (const key of fetchedRepoPRsRef.current) {
        const cacheKey = `repo-prs:${key}`
        if (dataCache.isFresh(cacheKey, intervalMs)) continue
        const [org, ...repoParts] = key.split('/')
        const repoName = repoParts.join('/')
        if (!org || !repoName) continue
        fetchRepoPRsForRepo(org, repoName, true)
      }
    }, intervalMs)
    return () => clearInterval(intervalId)
  }, [accounts.length, fetchRepoPRsForRepo, refreshInterval])

  useEffect(() => {
    if (!refreshInterval || refreshInterval <= 0 || accounts.length === 0) return
    const intervalMs = refreshInterval * MS_PER_MINUTE
    const intervalId = setInterval(() => {
      for (const key of fetchedSFLRef.current) {
        const cacheKey = `sfl-status:${key}`
        if (dataCache.isFresh(cacheKey, intervalMs)) continue
        const [org, ...repoParts] = key.split('/')
        const repoName = repoParts.join('/')
        if (!org || !repoName) continue
        fetchSFLStatusForRepo(org, repoName, true)
      }
    }, intervalMs)
    return () => clearInterval(intervalId)
  }, [accounts.length, fetchSFLStatusForRepo, refreshInterval])

  useEffect(() => {
    if (!refreshInterval || refreshInterval <= 0 || accounts.length === 0) return
    const intervalMs = refreshInterval * MS_PER_MINUTE
    const refreshRepoCounts = () => {
      for (const key of fetchedCountsRef.current) {
        const cacheKey = `repo-counts:${key}`
        if (dataCache.isFresh(cacheKey, intervalMs)) {
          continue
        }
        const [org, ...repoParts] = key.split('/')
        const repoName = repoParts.join('/')
        if (!org || !repoName) continue
        enqueueRef
          .current(
            async signal => {
              if (signal.aborted) throw new DOMException('Cancelled', 'AbortError')
              const client = new GitHubClient({ accounts }, 7)
              const result = await client.fetchRepoCounts(org, repoName)
              dataCache.set(cacheKey, result)
            },
            { name: `refresh-repo-counts-${key}`, priority: -1 }
          )
          .catch(error => {
            if (error instanceof DOMException && error.name === 'AbortError') return
            console.warn(`[RepoCountsRefresh] ${key} failed:`, error)
          })
      }
    }
    const intervalId = setInterval(refreshRepoCounts, intervalMs)
    return () => clearInterval(intervalId)
  }, [accounts, refreshInterval])

  const prItems: SidebarItem[] = [
    { id: 'pr-my-prs', label: 'My PRs' },
    { id: 'pr-needs-review', label: 'Needs Review' },
    { id: 'pr-need-a-nudge', label: 'Needs a nudge' },
    { id: 'pr-recently-merged', label: 'Recently Merged' },
  ]

  useEffect(() => {
    const viewIdByCacheKey=[REDACTED] string> = {
      'my-prs': 'pr-my-prs',
      'needs-review': 'pr-needs-review',
      'need-a-nudge': 'pr-need-a-nudge',
      'recently-merged': 'pr-recently-merged',
    }
    const unsubscribe = dataCache.subscribe(key => {
      const viewId = viewIdByCacheKey[key]
      if (!viewId) return
      const data = dataCache.get<PullRequest[]>(key)?.data || []
      setPrTreeData(prev => ({ ...prev, [viewId]: data }))
    })
    return unsubscribe
  }, [])

  const togglePRGroup = (itemId: string) => {
    setExpandedPrGroups(prev => {
      const next = new Set(prev)
      if (next.has(itemId)) next.delete(itemId)
      else next.add(itemId)
      return next
    })
  }

  const togglePRNode = (prViewId: string) => {
    setExpandedPRNodes(prev => {
      const next = new Set(prev)
      if (next.has(prViewId)) next.delete(prViewId)
      else next.add(prViewId)
      return next
    })
  }

  const openPRReview = (pr: PullRequest) => {
    window.dispatchEvent(
      new CustomEvent('pr-review:open', {
        detail: { prUrl: pr.url, prTitle: pr.title, prNumber: pr.id, repo: pr.repository, org: pr.org || '', author: pr.author },
      })
    )
  }

  const openTreePRContextMenu = (e: React.MouseEvent, pr: PullRequest) => {
    e.preventDefault()
    setPrContextMenu({ x: e.clientX, y: e.clientY, pr })
  }

  useEffect(() => {
    if (!prContextMenu) return
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setPrContextMenu(null)
    }
    document.addEventListener('keydown', handleKeyDown)
    return () => document.removeEventListener('keydown', handleKeyDown)
  }, [prContextMenu])

  const copyToClipboard = async (text: string) => {
    if (navigator.clipboard?.writeText) {
      await navigator.clipboard.writeText(text)
      return
    }
    const textArea = document.createElement('textarea')
    textArea.value = text
    textArea.style.position = 'fixed'
    textArea.style.opacity = '0'
    document.body.appendChild(textArea)
    textArea.select()
    document.execCommand('copy')
    document.body.removeChild(textArea)
  }

  const applyApproveToTree = useCallback((target: PullRequest) => {
    setPrTreeData(prev => {
      const next: Record<string, PullRequest[]> = { ...prev }
      for (const [groupId, items] of Object.entries(prev) as Array<[string, PullRequest[]]>) {
        next[groupId] = items.map(item => {
          if (item.id !== target.id || item.repository !== target.repository || item.source !== target.source || item.iApproved) return item
          return { ...item, iApproved: true, approvalCount: item.approvalCount + 1 }
        })
      }
      return next
    })
  }, [])

  const handleApprovePR = useCallback(
    async (pr: PullRequest) => {
      if (pr.iApproved) return
      const parsed = parseOwnerRepoFromUrl(pr.url)
      const owner = pr.org || parsed?.owner
      const repo = pr.repository || parsed?.repo
      if (!owner || !repo) return
      const prKey = `${pr.source}-${pr.repository}-${pr.id}`
      setApprovingPrKey(prKey)
      try {
        await enqueueRef.current(
          async signal => {
            if (signal.aborted) throw new DOMException('Cancelled', 'AbortError')
            const client = new GitHubClient({ accounts }, 7)
            await client.approvePullRequest(owner, repo, pr.id)
          },
          { name: `approve-sidebar-pr-${owner}-${repo}-${pr.id}` }
        )
        applyApproveToTree(pr)
      } catch (error) {
        if (error instanceof DOMException && error.name === 'AbortError') return
        console.error('Failed to approve PR from sidebar:', error)
      } finally {
        setApprovingPrKey(null)
      }
    },
    [accounts, applyApproveToTree]
  )

  return {
    prContextMenu,
    setPrContextMenu,
    approvingPrKey,
    bookmarkedRepoKeys,
    expandedSections,
    prItems,
    prTreeData,
    expandedPrGroups,
    expandedPRNodes,
    uniqueOrgs,
    orgRepos,
    orgMeta,
    loadingOrgs,
    expandedOrgs,
    expandedRepos,
    expandedRepoPRGroups,
    repoCounts,
    loadingRepoCounts,
    repoPrTreeData,
    sflStatusData,
    loadingSFLStatus,
    expandedSFLGroups,
    showBookmarkedOnly,
    setShowBookmarkedOnly,
    refreshTick,
    toggleSection,
    toggleOrg,
    toggleRepo,
    toggleRepoPRGroup,
    toggleSFLGroup,
    togglePRGroup,
    togglePRNode,
    openTreePRContextMenu,
    handleBookmarkToggle,
    handleApprovePR,
    copyToClipboard,
    openPRReview,
    toggleBookmarkRepoByValues,
  }
}

import {
  ChevronDown,
  ChevronRight,
  GitPullRequest,
  Building2,
} from 'lucide-react'
import { SidebarPRContextMenu } from './github-sidebar/SidebarPRContextMenu'
import { PRTreeSection } from './github-sidebar/PRTreeSection'
import { OrgRepoTree } from './github-sidebar/OrgRepoTree'
import { useGitHubSidebarData } from './github-sidebar/useGitHubSidebarData'

interface GitHubSidebarProps {
  onItemSelect: (itemId: string) => void
  selectedItem: string | null
  counts: Record<string, number>
  badgeProgress: Record<string, { progress: number; color: string; tooltip: string }>
}

export function GitHubSidebar({ onItemSelect, selectedItem, counts, badgeProgress }: GitHubSidebarProps) {
  const {
    prContextMenu, setPrContextMenu,
    approvingPrKey,
    bookmarkedRepoKeys,
    expandedSections,
    prItems,
    prTreeData,
    expandedPrGroups,
    expandedPRNodes,
    uniqueOrgs,
    orgRepos,
    orgMeta,
    loadingOrgs,
    expandedOrgs,
    expandedRepos,
    expandedRepoPRGroups,
    repoCounts,
    loadingRepoCounts,
    repoPrTreeData,
    sflStatusData,
    loadingSFLStatus,
    expandedSFLGroups,
    showBookmarkedOnly,
    setShowBookmarkedOnly,
    refreshTick,
    toggleSection,
    toggleOrg,
    toggleRepo,
    toggleRepoPRGroup,
    toggleSFLGroup,
    togglePRGroup,
    togglePRNode,
    openTreePRContextMenu,
    handleBookmarkToggle,
    handleApprovePR,
    copyToClipboard,
    openPRReview,
    toggleBookmarkRepoByValues,
  } = useGitHubSidebarData()

  return (
    <div className="sidebar-panel">
      {prContextMenu && (
        <SidebarPRContextMenu
          pr={prContextMenu.pr}
          x={prContextMenu.x}
          y={prContextMenu.y}
          approvingPrKey=[REDACTED]          bookmarkedRepoKeys={bookmarkedRepoKeys}
          onOpen={() => { window.shell.openExternal(prContextMenu.pr.url); setPrContextMenu(null) }}
          onCopyLink={async () => {
            try { await copyToClipboard(prContextMenu.pr.url) } catch (error) { console.error('Failed to copy PR link:', error) }
            setPrContextMenu(null)
          }}
          onAIReview={() => { openPRReview(prContextMenu.pr); setPrContextMenu(null) }}
          onApprove={async () => { await handleApprovePR(prContextMenu.pr); setPrContextMenu(null) }}
          onBookmark={async () => {
            const pr = prContextMenu.pr
            await toggleBookmarkRepoByValues(pr.org || '', pr.repository, pr.url.replace(/\/pull\/\d+$/, ''))
            setPrContextMenu(null)
          }}
          onClose={() => setPrContextMenu(null)}
        />
      )}
      <div className="sidebar-panel-header">
        <h2>GITHUB</h2>
      </div>
      <div className="sidebar-panel-content">
        {/* Pull Requests group */}
        <div className="sidebar-section">
          <div className="sidebar-section-header" role="button" tabIndex={0} onClick={() => toggleSection('pull-requests')} onKeyDown={e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggleSection('pull-requests') } }}>
            <div className="sidebar-section-title">
              {expandedSections.has('pull-requests') ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
              <span className="sidebar-section-icon"><GitPullRequest size={16} /></span>
              <span>Pull Requests</span>
            </div>
          </div>
          {expandedSections.has('pull-requests') && (
            <div className="sidebar-section-items">
              <PRTreeSection
                prItems={prItems}
                prTreeData={prTreeData}
                expandedPrGroups={expandedPrGroups}
                expandedPRNodes={expandedPRNodes}
                counts={counts}
                badgeProgress={badgeProgress}
                selectedItem={selectedItem}
                onItemSelect={onItemSelect}
                onTogglePRGroup={togglePRGroup}
                onTogglePRNode={togglePRNode}
                onContextMenu={openTreePRContextMenu}
              />
            </div>
          )}
        </div>

        {/* Organizations group */}
        <div className="sidebar-section">
          <div className="sidebar-section-header" role="button" tabIndex={0} onClick={() => toggleSection('organizations')} onKeyDown={e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggleSection('organizations') } }}>
            <div className="sidebar-section-title">
              {expandedSections.has('organizations') ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
              <span className="sidebar-section-icon"><Building2 size={16} /></span>
              <span>Organizations</span>
            </div>
          </div>
          {expandedSections.has('organizations') && (
            <OrgRepoTree
              uniqueOrgs={uniqueOrgs}
              orgRepos={orgRepos}
              orgMeta={orgMeta}
              loadingOrgs={loadingOrgs}
              expandedOrgs={expandedOrgs}
              expandedRepos={expandedRepos}
              expandedRepoPRGroups={expandedRepoPRGroups}
              expandedPRNodes={expandedPRNodes}
              repoCounts={repoCounts}
              loadingRepoCounts={loadingRepoCounts}
              repoPrTreeData={repoPrTreeData}
              sflStatusData={sflStatusData}
              loadingSFLStatus={loadingSFLStatus}
              expandedSFLGroups={expandedSFLGroups}
              bookmarkedRepoKeys={bookmarkedRepoKeys}
              showBookmarkedOnly={showBookmarkedOnly}
              selectedItem={selectedItem}
              refreshTick={refreshTick}
              onToggleOrg={toggleOrg}
              onToggleRepo={toggleRepo}
              onToggleRepoPRGroup={toggleRepoPRGroup}
              onToggleSFLGroup={toggleSFLGroup}
              onTogglePRNode={togglePRNode}
              onItemSelect={onItemSelect}
              onContextMenu={openTreePRContextMenu}
              onBookmarkToggle={handleBookmarkToggle}
              onToggleShowBookmarkedOnly={() => {
                setShowBookmarkedOnly(prev => {
                  const next = !prev
                  window.ipcRenderer.invoke('config:set-show-bookmarked-only', next).catch(() => {})
                  return next
                })
              }}
            />
          )}
        </div>
      </div>
    </div>
  )
}

