      authorAvatarUrl: c.user?.avatar_url || null,
      body: c.body || '',
      bodyHtml: null,
      createdAt: c.created_at,
      updatedAt: c.updated_at,
      url: c.html_url,
      diffHunk: null,
      reactions: [],
    }
  }

